'use client';

import { CloudUploadIcon, DownloadIcon, RefreshCwIcon } from 'lucide-react';
import Link from 'next/link';
import type { JSX } from 'react';

import type {
  DatabaseEngineManagedMongoApplication,
  DatabaseEngineManagedMongoDatabase,
  MongoSource,
} from '@/shared/contracts/database';
import { Badge, Button } from '@/shared/ui/primitives.public';

import {
  useDatabaseEngineActionsContext,
  useDatabaseEngineStateContext,
} from '../../context/DatabaseEngineContext';

const SOURCE_LABELS: Record<MongoSource, string> = {
  local: 'Local',
  cloud: 'Cloud',
};

export const buildManagedMongoCrudHref = (
  application: DatabaseEngineManagedMongoApplication,
  source: MongoSource = 'local'
): string =>
  `/admin/databases/engine?view=crud&application=${encodeURIComponent(
    application
  )}&source=${source}`;

const formatBytes = (bytes: number | null): string => {
  if (bytes === null) return 'n/a';
  if (bytes < 1024) return `${bytes} B`;
  const units = ['KB', 'MB', 'GB', 'TB'];
  let value = bytes / 1024;
  let unitIndex = 0;
  while (value >= 1024 && unitIndex < units.length - 1) {
    value /= 1024;
    unitIndex += 1;
  }
  return `${value.toFixed(value >= 10 ? 1 : 2)} ${units[unitIndex]}`;
};

const getEndpointStatusLabel = (
  endpoint: DatabaseEngineManagedMongoDatabase['local']
): string => {
  if (!endpoint.configured) return 'not configured';
  if (endpoint.reachable === true) return 'ready';
  if (endpoint.reachable === false) return 'unreachable';
  return 'unknown';
};

function ManagedMongoDatabaseScopeCard({
  activeApplication,
  activeSource,
  backupDisabled,
  database,
  syncDisabled,
}: {
  activeApplication: DatabaseEngineManagedMongoApplication;
  activeSource: MongoSource;
  backupDisabled: boolean;
  database: DatabaseEngineManagedMongoDatabase;
  syncDisabled: boolean;
}): JSX.Element {
  const { backupManagedMongo, syncManagedMongo } = useDatabaseEngineActionsContext();
  const isActive = database.application === activeApplication;
  const isLocalActive = isActive && activeSource === 'local';
  const isCloudActive = isActive && activeSource === 'cloud';
  const isBackupDisabled = backupDisabled || !database.canBackupLocal;
  const isPushDisabled = syncDisabled || !database.canPushToCloud;
  const isPullDisabled = syncDisabled || !database.canPullFromCloud;

  return (
    <div
      className={`rounded-md border p-3 ${
        isActive
          ? 'border-emerald-400/40 bg-emerald-500/10'
          : 'border-white/10 bg-black/20'
      }`}
    >
      <div className='flex flex-wrap items-start justify-between gap-3'>
        <div className='min-w-0 space-y-1'>
          <h3 className='truncate text-sm font-semibold text-white'>{database.label}</h3>
          <p className='text-xs text-gray-400'>
            Local {getEndpointStatusLabel(database.local)} - Cloud{' '}
            {getEndpointStatusLabel(database.cloud)}
          </p>
          <p className='text-xs text-gray-400'>
            Local {database.local.collectionCount.toLocaleString()} collections -{' '}
            {formatBytes(database.local.databaseSizeBytes)}
          </p>
          <p className='text-xs text-gray-400'>
            Cloud {database.cloud.collectionCount.toLocaleString()} collections -{' '}
            {formatBytes(database.cloud.databaseSizeBytes)}
          </p>
        </div>
        <Badge variant={isActive ? 'active' : 'outline'} className='border-white/10 text-xs'>
          {isActive ? `Open ${SOURCE_LABELS[activeSource]}` : 'Available'}
        </Badge>
      </div>

      {database.syncIssue !== null && database.syncIssue !== '' ? (
        <p className='mt-2 line-clamp-2 text-xs text-amber-100' title={database.syncIssue}>
          {database.syncIssue}
        </p>
      ) : null}

      <div className='mt-3 flex flex-wrap gap-2'>
        <Button asChild variant={isLocalActive ? 'secondary' : 'outline'} size='xs'>
          <Link href={buildManagedMongoCrudHref(database.application, 'local')}>Local Tables</Link>
        </Button>
        <Button asChild variant={isCloudActive ? 'secondary' : 'outline'} size='xs'>
          <Link href={buildManagedMongoCrudHref(database.application, 'cloud')}>Cloud Tables</Link>
        </Button>
        <Button
          type='button'
          variant='outline'
          size='xs'
          disabled={isBackupDisabled}
          onClick={() => {
            void backupManagedMongo(database.application);
          }}
        >
          <DownloadIcon className='size-3.5' />
          Backup
        </Button>
        <Button
          type='button'
          size='xs'
          disabled={isPushDisabled}
          onClick={() => {
            void syncManagedMongo('local_to_cloud', database.application);
          }}
        >
          <CloudUploadIcon className='size-3.5' />
          Push
        </Button>
        <Button
          type='button'
          variant='outline'
          size='xs'
          disabled={isPullDisabled}
          onClick={() => {
            void syncManagedMongo('cloud_to_local', database.application);
          }}
        >
          <RefreshCwIcon className='size-3.5' />
          Pull
        </Button>
      </div>
    </div>
  );
}

export function ManagedMongoScopePanel({
  activeApplication,
  activeSource,
}: {
  activeApplication: DatabaseEngineManagedMongoApplication;
  activeSource: MongoSource;
}): JSX.Element {
  const {
    managedMongoDatabases,
    operationControls,
    isBackingUpManagedMongo,
    isSyncingManagedMongo,
  } = useDatabaseEngineStateContext();
  const { backupManagedMongo, refetchAll, syncManagedMongo } = useDatabaseEngineActionsContext();

  if (managedMongoDatabases === undefined) {
    return (
      <div className='rounded-md border border-white/10 bg-black/20 p-3 text-sm text-gray-300'>
        Loading managed MongoDB files...
      </div>
    );
  }

  const backupDisabled =
    isBackingUpManagedMongo ||
    !operationControls.allowManualBackupRunNow ||
    !managedMongoDatabases.canBackupAllLocal;
  const syncDisabled =
    isSyncingManagedMongo ||
    !operationControls.allowManualFullSync ||
    !managedMongoDatabases.canPushAllToCloud;
  const pullDisabled =
    isSyncingManagedMongo ||
    !operationControls.allowManualFullSync ||
    !managedMongoDatabases.canPullAllFromCloud;
  const cardBackupDisabled =
    isBackingUpManagedMongo ||
    !operationControls.allowManualBackupRunNow ||
    !managedMongoDatabases.backupStorage.canWriteBackups;
  const cardSyncDisabled = isSyncingManagedMongo || !operationControls.allowManualFullSync;

  return (
    <div className='space-y-3 rounded-md border border-white/10 bg-card/30 p-3'>
      <div className='flex flex-wrap items-center justify-between gap-3'>
        <div className='space-y-1'>
          <h2 className='text-sm font-semibold text-white'>Managed MongoDB Files</h2>
          <p className='text-xs text-gray-400'>
            Backup root: {managedMongoDatabases.backupRoot}
          </p>
        </div>
        <div className='flex flex-wrap gap-2'>
          <Button type='button' variant='outline' size='xs' onClick={refetchAll}>
            <RefreshCwIcon className='size-3.5' />
            Refresh
          </Button>
          <Button
            type='button'
            variant='outline'
            size='xs'
            disabled={backupDisabled}
            onClick={() => {
              void backupManagedMongo('all');
            }}
          >
            <DownloadIcon className='size-3.5' />
            Backup All
          </Button>
          <Button
            type='button'
            size='xs'
            disabled={syncDisabled}
            onClick={() => {
              void syncManagedMongo('local_to_cloud', 'all');
            }}
          >
            <CloudUploadIcon className='size-3.5' />
            Push All
          </Button>
          <Button
            type='button'
            variant='outline'
            size='xs'
            disabled={pullDisabled}
            onClick={() => {
              void syncManagedMongo('cloud_to_local', 'all');
            }}
          >
            <RefreshCwIcon className='size-3.5' />
            Pull All
          </Button>
        </div>
      </div>

      <div className='grid gap-3 lg:grid-cols-2 xl:grid-cols-4'>
        {managedMongoDatabases.databases.map((database) => (
          <ManagedMongoDatabaseScopeCard
            key={database.application}
            activeApplication={activeApplication}
            activeSource={activeSource}
            backupDisabled={cardBackupDisabled}
            database={database}
            syncDisabled={cardSyncDisabled}
          />
        ))}
      </div>
    </div>
  );
}

'use client';

import Link from 'next/link';
import { CloudUploadIcon, DatabaseIcon, DownloadIcon, PencilIcon, RefreshCwIcon } from 'lucide-react';
import type { JSX } from 'react';

import type {
  DatabaseEngineManagedMongoApplicationTarget,
  DatabaseEngineManagedMongoCollectionStats,
  DatabaseEngineManagedMongoDatabase,
  DatabaseEngineManagedMongoEndpoint,
  DatabaseEngineMongoPendingSyncRequest,
  MongoSource,
} from '@/shared/contracts/database';
import { StatusBadge } from '@/shared/ui/data-display.public';
import { FormSection } from '@/shared/ui/forms-and-actions.public';
import { Button, Card } from '@/shared/ui/primitives.public';

import {
  useDatabaseEngineActionsContext,
  useDatabaseEngineStateContext,
} from '../../context/DatabaseEngineContext';
import { buildManagedMongoCrudHref } from '../crud/ManagedMongoScopePanel';

const SOURCE_LABELS: Record<MongoSource, string> = {
  local: 'Local',
  cloud: 'Cloud',
};

const isPendingSyncTarget = (
  pendingSync: DatabaseEngineMongoPendingSyncRequest | null,
  direction: 'cloud_to_local' | 'local_to_cloud',
  application: DatabaseEngineManagedMongoApplicationTarget
): boolean =>
  pendingSync !== null &&
  pendingSync.direction === direction &&
  pendingSync.application === application;

const formatBytes = (bytes: number | null): string => {
  if (bytes === null) return 'n/a';
  if (bytes < 1024) return `${bytes} B`;
  const units = ['KB', 'MB', 'GB', 'TB'];
  let value = bytes / 1024;
  let unitIndex = 0;
  while (value >= 1024 && unitIndex < units.length - 1) {
    value /= 1024;
    unitIndex += 1;
  }
  return `${value.toFixed(value >= 10 ? 1 : 2)} ${units[unitIndex]}`;
};

const getEndpointStatus = (
  endpoint: DatabaseEngineManagedMongoEndpoint
): { status: string; variant: 'active' | 'error' | 'pending' } => {
  if (!endpoint.configured) return { status: 'Not configured', variant: 'pending' };
  if (endpoint.reachable === true) return { status: 'Reachable', variant: 'active' };
  if (endpoint.reachable === false) return { status: 'Unreachable', variant: 'error' };
  return { status: 'Unknown', variant: 'pending' };
};

function CollectionSizeList({
  collections,
}: {
  collections: DatabaseEngineManagedMongoCollectionStats[];
}): JSX.Element {
  if (collections.length === 0) {
    return <p className='text-xs text-gray-400'>No collection stats available.</p>;
  }

  return (
    <div className='max-h-52 overflow-auto rounded-md border border-white/10'>
      <table className='w-full text-left text-[11px]'>
        <thead className='sticky top-0 bg-gray-950 text-gray-400'>
          <tr>
            <th className='px-2 py-1.5 font-medium'>Collection</th>
            <th className='px-2 py-1.5 text-right font-medium'>Docs</th>
            <th className='px-2 py-1.5 text-right font-medium'>Size</th>
          </tr>
        </thead>
        <tbody>
          {collections.map((collection) => (
            <tr key={collection.name} className='border-t border-white/10 text-gray-300'>
              <td className='max-w-40 truncate px-2 py-1.5 font-mono' title={collection.name}>
                {collection.name}
              </td>
              <td className='px-2 py-1.5 text-right'>
                {collection.documentCount?.toLocaleString() ?? 'n/a'}
              </td>
              <td className='px-2 py-1.5 text-right'>
                {formatBytes(collection.totalSizeBytes)}
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

function EndpointPanel({
  endpoint,
}: {
  endpoint: DatabaseEngineManagedMongoEndpoint;
}): JSX.Element {
  const status = getEndpointStatus(endpoint);

  return (
    <div className='space-y-3 rounded-md border border-white/10 bg-black/20 p-3'>
      <div className='flex items-start justify-between gap-2'>
        <div className='space-y-1'>
          <h4 className='text-xs font-semibold uppercase text-gray-300'>
            {SOURCE_LABELS[endpoint.source]}
          </h4>
          <p className='text-xs text-gray-400'>{endpoint.dbName ?? 'No database selected'}</p>
        </div>
        <StatusBadge status={status.status} variant={status.variant} size='sm' />
      </div>

      <div className='space-y-1 text-xs text-gray-300'>
        <p className='truncate' title={endpoint.maskedUri ?? ''}>
          {endpoint.maskedUri ?? 'No URI configured'}
        </p>
        <p>Database size: {formatBytes(endpoint.databaseSizeBytes)}</p>
        <p>Collections: {endpoint.collectionCount.toLocaleString()}</p>
        <p>Collection storage: {formatBytes(endpoint.collectionsSizeBytes)}</p>
        {endpoint.healthError !== null && endpoint.healthError !== '' ? <p className='text-rose-200'>{endpoint.healthError}</p> : null}
      </div>

      <CollectionSizeList collections={endpoint.collections} />
    </div>
  );
}

function ManagedDatabaseCard({
  database,
  backupDisabled,
  syncDisabled,
  pendingSync,
}: {
  database: DatabaseEngineManagedMongoDatabase;
  backupDisabled: boolean;
  syncDisabled: boolean;
  pendingSync: DatabaseEngineMongoPendingSyncRequest | null;
}): JSX.Element {
  const { backupManagedMongo, syncManagedMongo } = useDatabaseEngineActionsContext();
  const isBackupDisabled = backupDisabled || !database.canBackupLocal;
  const isPushDisabled = syncDisabled || !database.canPushToCloud;
  const isPullDisabled = syncDisabled || !database.canPullFromCloud;
  const isPushing = isPendingSyncTarget(pendingSync, 'local_to_cloud', database.application);
  const isPulling = isPendingSyncTarget(pendingSync, 'cloud_to_local', database.application);

  return (
    <Card variant='subtle' padding='md' className='space-y-4 border-white/10'>
      <div className='flex flex-wrap items-start justify-between gap-3'>
        <div className='space-y-1'>
          <h3 className='flex items-center gap-2 text-sm font-semibold text-white'>
            <DatabaseIcon className='size-4 text-emerald-200' />
            {database.label}
          </h3>
          {database.syncIssue !== null && database.syncIssue !== '' ? (
            <p className='text-xs leading-relaxed text-amber-100'>{database.syncIssue}</p>
          ) : null}
        </div>
        <div className='flex flex-wrap gap-2'>
          <Button asChild type='button' variant='outline' size='sm'>
            <Link href={buildManagedMongoCrudHref(database.application, 'local')}>
              <PencilIcon className='size-3.5' />
              Local Tables
            </Link>
          </Button>
          <Button asChild type='button' variant='outline' size='sm'>
            <Link href={buildManagedMongoCrudHref(database.application, 'cloud')}>
              <PencilIcon className='size-3.5' />
              Cloud Tables
            </Link>
          </Button>
          <Button
            type='button'
            variant='outline'
            size='sm'
            disabled={isBackupDisabled}
            onClick={() => {
              void backupManagedMongo(database.application);
            }}
          >
            <DownloadIcon className='size-3.5' />
            Backup
          </Button>
          <Button
            type='button'
            size='sm'
            disabled={isPushDisabled}
            loading={isPushing}
            loadingText='Pushing...'
            onClick={() => {
              void syncManagedMongo('local_to_cloud', database.application);
            }}
          >
            <CloudUploadIcon className='size-3.5' />
            Push
          </Button>
          <Button
            type='button'
            variant='outline'
            size='sm'
            disabled={isPullDisabled}
            loading={isPulling}
            loadingText='Pulling...'
            onClick={() => {
              void syncManagedMongo('cloud_to_local', database.application);
            }}
          >
            <RefreshCwIcon className='size-3.5' />
            Pull
          </Button>
        </div>
      </div>

      <div className='grid gap-4 xl:grid-cols-2'>
        <EndpointPanel endpoint={database.local} />
        <EndpointPanel endpoint={database.cloud} />
      </div>
    </Card>
  );
}

export function DatabaseEngineManagedMongoSection(): JSX.Element {
  const {
    managedMongoDatabases,
    operationControls,
    isBackingUpManagedMongo,
    isSyncingManagedMongo,
    isSyncingMongoSources,
    mongoSourceState,
    pendingMongoSourceSync,
  } = useDatabaseEngineStateContext();
  const { backupManagedMongo, syncManagedMongo, refetchAll } = useDatabaseEngineActionsContext();

  if (managedMongoDatabases === undefined) {
    return (
      <FormSection title='Managed Application Databases'>
        <p className='text-sm text-muted-foreground'>Loading managed database status...</p>
      </FormSection>
    );
  }

  const backupDisabled =
    isBackingUpManagedMongo ||
    !operationControls.allowManualBackupRunNow ||
    !managedMongoDatabases.canBackupAllLocal;
  const backupStorageDisabled = !managedMongoDatabases.backupStorage.canWriteBackups;
  const isMongoSyncBusy =
    isSyncingManagedMongo ||
    isSyncingMongoSources ||
    pendingMongoSourceSync !== null ||
    mongoSourceState?.syncInProgress !== null;
  const syncDisabled =
    isMongoSyncBusy ||
    !operationControls.allowManualFullSync ||
    !managedMongoDatabases.canPushAllToCloud;
  const pullDisabled =
    isMongoSyncBusy ||
    !operationControls.allowManualFullSync ||
    !managedMongoDatabases.canPullAllFromCloud;
  const isPushingAll = isPendingSyncTarget(pendingMongoSourceSync, 'local_to_cloud', 'all');
  const isPullingAll = isPendingSyncTarget(pendingMongoSourceSync, 'cloud_to_local', 'all');

  return (
    <FormSection title='Managed Application Databases' className='space-y-0'>
      <div className='space-y-4'>
        <Card variant='subtle' padding='md' className='space-y-3 border-white/10'>
          <div className='flex flex-wrap items-center justify-between gap-3'>
            <div className='space-y-1 text-xs text-gray-300'>
              <p>Backup root: {managedMongoDatabases.backupRoot}</p>
              <p>
                Backup free: {formatBytes(managedMongoDatabases.backupStorage.availableBytes)} /
                required {formatBytes(managedMongoDatabases.backupStorage.requiredFreeBytes)}
              </p>
              <p>Last checked: {managedMongoDatabases.timestamp}</p>
            </div>
            <div className='flex flex-wrap gap-2'>
              <Button type='button' variant='outline' size='sm' onClick={refetchAll}>
                <RefreshCwIcon className='size-3.5' />
                Refresh
              </Button>
              <Button
                type='button'
                variant='outline'
                size='sm'
                disabled={backupDisabled}
                onClick={() => {
                  void backupManagedMongo('all');
                }}
              >
                <DownloadIcon className='size-3.5' />
                Backup All
              </Button>
              <Button
                type='button'
                size='sm'
                disabled={syncDisabled}
                loading={isPushingAll}
                loadingText='Pushing all...'
                onClick={() => {
                  void syncManagedMongo('local_to_cloud', 'all');
                }}
              >
                <CloudUploadIcon className='size-3.5' />
                Push All
              </Button>
              <Button
                type='button'
                variant='outline'
                size='sm'
                disabled={pullDisabled}
                loading={isPullingAll}
                loadingText='Pulling all...'
                onClick={() => {
                  void syncManagedMongo('cloud_to_local', 'all');
                }}
              >
                <RefreshCwIcon className='size-3.5' />
                Pull All
              </Button>
            </div>
          </div>
          {managedMongoDatabases.issues.length > 0 ? (
            <div className='space-y-1 rounded-md border border-amber-400/30 bg-amber-500/10 p-3 text-xs text-amber-100'>
              {managedMongoDatabases.issues.map((issue) => (
                <p key={issue}>{issue}</p>
              ))}
            </div>
          ) : null}
        </Card>

        {managedMongoDatabases.databases.map((database) => (
          <ManagedDatabaseCard
            key={database.application}
            database={database}
            backupDisabled={
              isBackingUpManagedMongo ||
              !operationControls.allowManualBackupRunNow ||
              backupStorageDisabled
            }
            syncDisabled={isMongoSyncBusy || !operationControls.allowManualFullSync}
            pendingSync={pendingMongoSourceSync}
          />
        ))}
      </div>
    </FormSection>
  );
}

'use client';

import type {
  DatabaseEngineManagedMongoApplication,
  DatabaseEngineManagedMongoApplicationTarget,
  DatabaseEngineMongoAppSyncStatus,
  DatabaseEngineMongoAppSyncStatuses,
  DatabaseEngineMongoPendingSyncRequest,
  DatabaseEngineMongoSyncInProgress,
} from '@/shared/contracts/database';
import { Button, Card, Tooltip } from '@/shared/ui/primitives.public';

import type { JSX } from 'react';

const MONGO_SYNC_APPLICATIONS: DatabaseEngineManagedMongoApplication[] = [
  'geminitestapp',
  'studiq',
  'cms-builder',
  'products',
];

const APPLICATION_LABELS: Record<DatabaseEngineManagedMongoApplication, string> = {
  geminitestapp: 'GeminiTest App',
  studiq: 'StudiQ',
  'cms-builder': 'CMS Builder',
  products: 'Ecommerce',
};

const APPLICATION_TARGET_LABELS: Record<DatabaseEngineManagedMongoApplicationTarget, string> = {
  all: 'All apps',
  ...APPLICATION_LABELS,
};

const resolveSyncEndpoints = (
  direction: 'cloud_to_local' | 'local_to_cloud'
): { source: 'cloud' | 'local'; target: 'cloud' | 'local' } =>
  direction === 'cloud_to_local'
    ? { source: 'cloud', target: 'local' }
    : { source: 'local', target: 'cloud' };

const formatSyncAction = (direction: 'cloud_to_local' | 'local_to_cloud'): string =>
  direction === 'cloud_to_local' ? 'Pulling' : 'Pushing';

const isPendingSyncTarget = (
  pendingSync: DatabaseEngineMongoPendingSyncRequest | null,
  direction: 'cloud_to_local' | 'local_to_cloud',
  application: DatabaseEngineManagedMongoApplicationTarget
): boolean =>
  pendingSync !== null &&
  pendingSync.direction === direction &&
  pendingSync.application === application;

const resolveUnavailableSyncMessage = (params: {
  allowManualFullSync: boolean;
  hasDualSourceConfigured: boolean;
  canSync: boolean;
  syncIssue: string | null;
}): string | null => {
  const { allowManualFullSync, hasDualSourceConfigured, canSync, syncIssue } = params;

  if (!allowManualFullSync) {
    return 'Manual full sync is disabled by Database Engine controls.';
  }

  if (!hasDualSourceConfigured) {
    return 'Configure both local and cloud URIs in the effective env and set MONGODB_ACTIVE_SOURCE_DEFAULT in the winning file to use dual-source mode.';
  }

  if (!canSync) {
    return syncIssue !== null && syncIssue !== ''
      ? syncIssue
      : 'MongoDB source sync is unavailable right now.';
  }

  return null;
};

function MongoSyncButtons({
  buttonsDisabled,
  primaryLabel,
  secondaryLabel,
  pendingSync,
  onSync,
}: {
  buttonsDisabled: boolean;
  primaryLabel: string;
  secondaryLabel: string;
  pendingSync: DatabaseEngineMongoPendingSyncRequest | null;
  onSync: (direction: 'cloud_to_local' | 'local_to_cloud') => void;
}): JSX.Element {
  const isPullingAll = isPendingSyncTarget(pendingSync, 'cloud_to_local', 'all');
  const isPushingAll = isPendingSyncTarget(pendingSync, 'local_to_cloud', 'all');

  return (
    <div className='flex flex-wrap gap-3'>
      <Button
        type='button'
        disabled={buttonsDisabled}
        loading={isPullingAll}
        loadingText='Pulling all apps...'
        onClick={() => onSync('cloud_to_local')}
      >
        {primaryLabel}
      </Button>
      <Button
        type='button'
        disabled={buttonsDisabled}
        loading={isPushingAll}
        loadingText='Pushing all apps...'
        onClick={() => onSync('local_to_cloud')}
      >
        {secondaryLabel}
      </Button>
    </div>
  );
}

function EndpointIndicator({
  label,
  configured,
  reachable,
}: {
  label: string;
  configured: boolean;
  reachable: boolean | null;
}): JSX.Element {
  const getStatus = (): string => {
    if (!configured) return 'Missing';
    if (reachable === true) return 'Reachable';
    return 'Unreachable';
  };

  const status = getStatus();
  const colorClass =
    status === 'Reachable'
      ? 'bg-emerald-400/15 text-emerald-200'
      : status === 'Missing'
        ? 'bg-amber-400/15 text-amber-200'
        : 'bg-red-400/15 text-red-200';

  return (
    <span className={`rounded-md px-2 py-1 text-[11px] font-medium ${colorClass}`}>
      {label}: {status}
    </span>
  );
}

function AppSyncButtons({
  status,
  disabled,
  pendingSync,
  onSync,
}: {
  status: DatabaseEngineMongoAppSyncStatus;
  disabled: boolean;
  pendingSync: DatabaseEngineMongoPendingSyncRequest | null;
  onSync: (
    direction: 'cloud_to_local' | 'local_to_cloud',
    application: DatabaseEngineManagedMongoApplication
  ) => void;
}): JSX.Element {
  const issue = status.issue ?? 'MongoDB source sync is unavailable for this application.';
  const buttonsDisabled = disabled || !status.canSync;
  const isPulling = isPendingSyncTarget(pendingSync, 'cloud_to_local', status.application);
  const isPushing = isPendingSyncTarget(pendingSync, 'local_to_cloud', status.application);

  return (
    <Tooltip content={buttonsDisabled && !status.canSync ? issue : ''} side='left'>
      <div className='flex shrink-0 flex-wrap gap-2'>
        <Button
          type='button'
          size='xs'
          disabled={buttonsDisabled}
          loading={isPulling}
          loadingText='Pulling...'
          aria-label={`Pull ${APPLICATION_LABELS[status.application]} cloud to local`}
          title={status.canSync ? undefined : issue}
          onClick={() => onSync('cloud_to_local', status.application)}
        >
          Pull
        </Button>
        <Button
          type='button'
          size='xs'
          disabled={buttonsDisabled}
          loading={isPushing}
          loadingText='Pushing...'
          aria-label={`Push ${APPLICATION_LABELS[status.application]} local to cloud`}
          title={status.canSync ? undefined : issue}
          onClick={() => onSync('local_to_cloud', status.application)}
        >
          Push
        </Button>
      </div>
    </Tooltip>
  );
}

function AppStatusRow({
