      {point && (
        <div className='mb-4 p-3' style={{ border: '1px solid var(--border)', background: 'var(--bg)' }}>
          <div style={{ fontFamily: 'var(--font-mono)', fontSize: '0.78rem', color: 'var(--fg)', letterSpacing: '0.08em' }}>
