            <div className='space-y-3'>
              <p className='type-label' style={{ color: 'var(--accent)' }}>
                {loadError}
              </p>
              <ManualInpostPointInput
                locale={locale}
                value={manualValue}
                error={error}
                invalid={manualInvalid}
                onChange={onManualValueChange}
