type DuelCurrentEntry = {
  displayName: string;
  lastPlayedAt: string;
  losses: number;
  matches: number;
  ties: number;
  winRate: number;
  wins: number;
};

type DuelOpponent = {
  displayName: string;
  lastPlayedAt: string;
  learnerId: string;
};

export type ResultsDuelsState = {
  actionError: string | null;
  createRematch: (opponentLearnerId: string) => Promise<string | null>;
  currentEntry: DuelCurrentEntry | null;
  currentRank: number | null;
  error: string | null;
  isActionPending: boolean;
  isLoading: boolean;
  isRestoringAuth: boolean;
  opponents: DuelOpponent[];
  pendingOpponentLearnerId: string | null;
  refresh: () => Promise<void>;
};

function renderDuelStatus(duelResults: ResultsDuelsState, copy: KangurMobileCopy): React.JSX.Element | null {
  if (Boolean(duelResults.isRestoringAuth) || Boolean(duelResults.isLoading)) {
    return (
      <Text style={{ color: '#475569', fontSize: 14, lineHeight: 20 }}>
        {copy({
          de: 'Der Duellstand in den Ergebnissen wird geladen.',
          en: 'Loading the duel standing in results.',
          pl: 'Pobieramy stan pojedynków w wynikach.',
        })}
      </Text>
    );
  }
  if (duelResults.error !== null && duelResults.error !== '') {
    return (
      <View style={{ gap: 10 }}>
        <Text style={{ color: '#b91c1c', fontSize: 14, lineHeight: 20 }}>
          {duelResults.error}
        </Text>
        <ActionButton
          label={copy({
            de: 'Duelle aktualisieren',
            en: 'Refresh duels',
            pl: 'Odśwież pojedynki',
          })}
          onPress={() => {
            void duelResults.refresh();
          }}
          stretch
          style={{ borderRadius: 16 }}
          tone='primary'
          verticalPadding={12}
        />
      </View>
    );
  }
  return null;
}

