export type Tone = {
  backgroundColor: string;
  borderColor: string;
  textColor: string;
};

export const BASE_TONE: Tone = {
  backgroundColor: '#f8fafc',
  borderColor: '#cbd5e1',
  textColor: '#475569',
};

export const SUCCESS_TONE: Tone = {
  backgroundColor: '#ecfdf5',
  borderColor: '#a7f3d0',
  textColor: '#047857',
};

export const WARNING_TONE: Tone = {
  backgroundColor: '#fffbeb',
  borderColor: '#fde68a',
  textColor: '#b45309',
};

export const INDIGO_TONE: Tone = {
  backgroundColor: '#eef2ff',
  borderColor: '#c7d2fe',
  textColor: '#4338ca',
};

export function ChoiceCardButton({
  description,
  disabled = false,
  helperText,
  indexLabel,
  label,
  onPress,
  tone = BASE_TONE,
}: {
  description?: string;
  disabled?: boolean;
  helperText?: ReactNode;
  indexLabel: string;
  label: string;
  onPress: () => void;
  tone?: Tone;
}): React.JSX.Element {
  return (
