import {
  BASE_TONE,
  ChoiceCardButton,
  INDIGO_TONE,
  SUCCESS_TONE,
  WARNING_TONE,
  type Tone,
} from '../shared/KangurAssessmentUi';
import {
  OutlineLink,
  PrimaryButton,
  SectionCard,
  StatusPill,
} from '../shared/KangurAssessmentUi';
